                                    className={`relative p-5 pr-20 rounded-[1.5rem] cursor-pointer transition-all duration-300 border group select-none
                                        ${isActive 
                                            ? 'bg-gradient-to-r from-pink-50/80 to-white/90 border-pink-200 shadow-md ring-1 ring-pink-100 scale-[1.02]' 
                                            : 'bg-white/60 border-white/40 hover:bg-white/80 hover:shadow-md hover:border-white/80 hover:scale-[1.01]'
                                        }
                                        ${isSelected ? 'ring-2 ring-indigo-500 bg-indigo-50/80' : ''}
                                    `}
                                >
                                    <div className="flex gap-4">
                                        {/* Selection Slot (Appears on Double Click / Mode) */}
                                        {isSelectionMode && (
