                                                <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${isSelected ? 'bg-indigo-500 border-indigo-500 text-white shadow-md shadow-indigo-300' : 'border-slate-300 bg-white hover:border-indigo-400'}`}>
