                                                <span className={`text-[10px] font-bold whitespace-nowrap ${isActive ? 'text-pink-400' : 'text-slate-400'}`}>{new Date(update.submitted_at).toLocaleDateString()}</span>
                                            </div>
                                            <p className={`text-xs line-clamp-2 leading-relaxed ${isActive ? 'text-pink-900/80' : 'text-slate-500'}`}>{update.update_text}</p>
                                        </div>
                                    </div>

                                    {/* Delete Button (Always Visible & Red) */}
                                    <button 
                                        onClick={(e) => handleDeleteClick(update.id, e)}
