                                            )}

                                            {/* Logic to hide reasons if adding a job (focus on positive action) or if related */}
                                            {(analysis.intent === 'UNEMPLOYED' || analysis.intent === 'RETIRE') && (analysis.unemployed_reasons || analysis.retirement_reason) && (
