                                        {/* Decorative BG */}
                                        <div className="absolute top-0 right-0 w-48 h-48 bg-gradient-to-b from-indigo-50 to-transparent rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 -z-0 opacity-50"></div>
                                    </div>
                                ) : (
