import { GoogleGenAI } from "@google/genai";
import { supabase } from '../lib/supabaseClient';

const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

const MODEL = "gemini-2.5-flash-latest";

// --- Context Gathering ---
const getSystemContext = async () => {
    // Fetch aggregate data to feed the AI
    const { data: empData } = await supabase.from('employment_information').select('employment_status, industry, salary_range, current_job_level, job_alignment');
    const { count: studentCount } = await supabase.from('students').select('*', { count: 'exact', head: true });
    const { count: alumniCount } = await supabase.from('alumni').select('*', { count: 'exact', head: true });
    const { count: pendingApps } = await supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('application_status', 'Pending');

    // Simple aggregations
    const statusCounts: Record<string, number> = {};
    const industryCounts: Record<string, number> = {};
    const alignmentCounts: Record<string, number> = {};

    empData?.forEach(r => {
        const status = r.employment_status || 'Unknown';
        statusCounts[status] = (statusCounts[status] || 0) + 1;

        if (r.industry) industryCounts[r.industry] = (industryCounts[r.industry] || 0) + 1;
        if (r.job_alignment) alignmentCounts[r.job_alignment] = (alignmentCounts[r.job_alignment] || 0) + 1;
    });

    return {
        total_users: (studentCount || 0) + (alumniCount || 0),
        new_graduates: studentCount || 0,
        old_alumni: alumniCount || 0,
        pending_job_applications: pendingApps || 0,
        employment_stats: statusCounts,
        top_industries: Object.entries(industryCounts).sort((a,b) => b[1] - a[1]).slice(0, 5),
        alignment_stats: alignmentCounts
    };
};

export const sendMessageToPaulo = async (message: string, history: any[]) => {
    const contextData = await getSystemContext();

    const systemPrompt = `
    You are P.A.U.L.O (Placement, Alumni, University Linkages Office), an advanced AI assistant for the Admin of Laguna University's Alumni Tracer System.

    **Your Personality:** Professional, data-driven, yet helpful and conversational (like Jarvis). You assist with tasks, visualize data, and answer questions.

    **Current System Data (Real-time Context):**
    ${JSON.stringify(contextData)}

    **Capabilities:**
    1. Answer questions about the data above.
    2. Analyze trends.
    3. Generate Charts.

    **Chart Generation Rules:**
    If the user asks to visualize data (e.g., "Show me a chart of employment status", "Graph the industries"), you MUST output a specific JSON structure at the END of your text response.

    Format for Charts:
    :::CHART_DATA:::
    {
      "type": "bar" | "pie",
      "title": "Chart Title",
      "data": [
        {"name": "Label1", "value": 10},
        {"name": "Label2", "value": 20}
      ]
    }
    :::END_CHART:::

    **General Rules:**
    - Be concise.
    - If asked about data you don't have in the context, say you don't have access to that specific granular record yet, but offer summary stats.
    - Do not make up numbers. Use the provided context.
    `;

    try {
        // Format history for Gemini
        const chatHistory = history.map(h => ({
            role: h.sender === 'user' ? 'user' : 'model',
            parts: [{ text: h.text }]
        }));

        const chat = ai.chats.create({
            model: MODEL,
            config: {
                systemInstruction: systemPrompt,
                temperature: 0.7,
            },
            history: chatHistory
        });

        const result = await chat.sendMessage({ message: message });
        const responseText = result.text;

        // Parse for Chart Data
        let chartData = null;
        let cleanText = responseText;

        const chartRegex = /:::CHART_DATA:::([\s\S]*?):::END_CHART:::/;
        const match = responseText.match(chartRegex);

        if (match && match[1]) {
            try {
                chartData = JSON.parse(match[1]);
                cleanText = responseText.replace(match[0], '').trim();
            } catch (e) {
                console.error("Failed to parse chart JSON from AI", e);
            }
        }

        return {
            text: cleanText,
            chart: chartData
        };

    } catch (error) {
        console.error("PAULO Error:", error);
        return { text: "I'm encountering a connection error with my neural link. Please try again.", chart: null };
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { Send, Bot, User, Sparkles, BarChart2, PieChart as PieIcon, RefreshCw, StopCircle } from 'lucide-react';
import { sendMessageToPaulo } from '../services/pauloService';
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, PieChart, Pie, Cell, Legend } from 'recharts';

interface Message {
  id: string;
  sender: 'user' | 'paulo';
  text: string;
  chart?: {
    type: 'bar' | 'pie';
    title: string;
    data: { name: string; value: number }[];
  } | null;
  timestamp: Date;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#10b981', '#f59e0b', '#3b82f6'];

const PauloPage: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      sender: 'paulo',
      text: "Hello, Administrator. I am P.A.U.L.O. (Placement, Alumni, University Linkages Office) Assistant. I have access to the latest system metrics. How can I assist you today?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const scrollToBottom = () => {
    scrollRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      sender: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Call AI
    const history = messages.map(m => ({ sender: m.sender, text: m.text }));
    const response = await sendMessageToPaulo(userMsg.text, history);

    const botMsg: Message = {
      id: (Date.now() + 1).toString(),
      sender: 'paulo',
      text: response.text,
      chart: response.chart,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, botMsg]);
    setIsTyping(false);
  };

  const handleQuickPrompt = (prompt: string) => {
      setInput(prompt);
      // Optional: Auto submit
      // handleSend(); 
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 relative overflow-hidden">

        {/* Background Effects */}
        <div className="absolute inset-0 pointer-events-none">
            <div className="absolute -top-[20%] -left-[10%] w-[50%] h-[50%] rounded-full bg-indigo-500/5 blur-[120px]"></div>
            <div className="absolute bottom-[10%] -right-[10%] w-[40%] h-[40%] rounded-full bg-blue-500/5 blur-[100px]"></div>
        </div>

        {/* Header */}
        <div className="bg-white/80 backdrop-blur-xl border-b border-slate-200 p-4 flex items-center justify-between z-20 sticky top-0">
            <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-600 to-blue-600 flex items-center justify-center shadow-lg shadow-indigo-200">
                    <Bot className="text-white w-6 h-6" />
                </div>
                <div>
                    <h1 className="font-black text-slate-800 text-lg tracking-tight flex items-center gap-2">
                        P.A.U.L.O. <span className="px-2 py-0.5 rounded-full bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase">AI Online</span>
                    </h1>
                    <p className="text-xs text-slate-500 font-medium">Placement Alumni University Linkages Office Assistant</p>
                </div>
            </div>
            <button 
                onClick={() => setMessages([{ id: 'reset', sender: 'paulo', text: "Memory cleared. How can I help?", timestamp: new Date() }])}
                className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                title="Reset Conversation"
            >
                <RefreshCw size={18} />
            </button>
        </div>

        {/* Chat Area */}
        <div className="flex-grow overflow-y-auto p-4 md:p-6 space-y-6 z-10 custom-scrollbar">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex w-full ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`flex max-w-[85%] md:max-w-[75%] gap-3 ${msg.sender === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>

