            <div ref={scrollRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-slate-200 z-20">
            {/* Quick Prompts */}
            {messages.length < 3 && (
                <div className="flex gap-2 overflow-x-auto pb-3 scrollbar-hide mb-2">
