import { GoogleGenAI } from "@google/genai";
import { supabase } from '../lib/supabaseClient';

const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

// Using gemini-3-flash-preview for reliable chat and reasoning
const MODEL = "gemini-3-flash-preview";

// --- Context Gathering ---
const getSystemContext = async () => {
    // Fetch aggregate data to feed the AI
    const { data: empData } = await supabase.from('employment_information').select('employment_status, industry, salary_range, current_job_level, job_alignment');
    const { count: studentCount } = await supabase.from('students').select('*', { count: 'exact', head: true });
    const { count: alumniCount } = await supabase.from('alumni').select('*', { count: 'exact', head: true });
    const { count: pendingApps } = await supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('application_status', 'Pending');

    // Simple aggregations
    const statusCounts: Record<string, number> = {};
    const industryCounts: Record<string, number> = {};
    const alignmentCounts: Record<string, number> = {};

    empData?.forEach(r => {
        const status = r.employment_status || 'Unknown';
        statusCounts[status] = (statusCounts[status] || 0) + 1;

        if (r.industry) industryCounts[r.industry] = (industryCounts[r.industry] || 0) + 1;
        if (r.job_alignment) alignmentCounts[r.job_alignment] = (alignmentCounts[r.job_alignment] || 0) + 1;
    });

    // Get top industries sorted
    const topIndustries = Object.entries(industryCounts)
        .sort((a,b) => b[1] - a[1])
        .slice(0, 5)
        .map(([name, count]) => ({ name, count }));

    return {
        total_users: (studentCount || 0) + (alumniCount || 0),
        new_graduates: studentCount || 0,
        old_alumni: alumniCount || 0,
        pending_job_applications: pendingApps || 0,
        employment_stats: statusCounts,
        top_industries: topIndustries,
        alignment_stats: alignmentCounts
    };
};

