import { GoogleGenAI } from "@google/genai";
import { supabase } from '../lib/supabaseClient';

const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

// Using gemini-3-flash-preview for reliable chat and reasoning
const MODEL = "gemini-3-flash-preview";

// --- Context Gathering ---
const getSystemContext = async () => {
    try {
        // 1. Fetch Employment Data
        const { data: empData, error: empError } = await supabase
            .from('employment_information')
            .select('survey_response_id, employment_status, industry, job_alignment');

        if (empError) throw empError;

        // 2. Fetch Survey Mapping
        const { data: surveys, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id, student_id, alumni_id, respondent_type');

        if (surveyError) throw surveyError;

        // 3. Fetch User Profiles (Students & Alumni) for Program/Batch info
        const [ { data: students }, { data: alumni } ] = await Promise.all([
            supabase.from('students').select('id, program, year_level'),
            supabase.from('alumni').select('id, program, year_level')
        ]);

        // --- Data Linking & Aggregation ---

        // Maps for O(1) lookup
        const surveyMap = new Map(surveys?.map((s: any) => [s.id, s]));
        const studentMap = new Map(students?.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni?.map((a: any) => [a.id, a]));

        // Aggregation Containers
        // Key format: "Program|Batch|Status" -> Count
        const detailedStats: Record<string, number> = {};
        const industryStats: Record<string, number> = {};

        let totalRecords = 0;

        empData?.forEach(record => {
            const survey = surveyMap.get(record.survey_response_id);
            if (!survey) return;

            let userProfile: any = null;
            if (survey.respondent_type === 'student') {
                userProfile = studentMap.get(survey.student_id);
            } else {
                userProfile = alumniMap.get(survey.alumni_id);
            }

            if (userProfile) {
                totalRecords++;
                const program = userProfile.program || "Unknown Program";
                const batch = userProfile.year_level || "Unknown Batch";
                const status = record.employment_status || "Unknown Status";

                // 1. Detailed Aggregation for Filtering
                const key = `${program}|${batch}|${status}`;
                detailedStats[key] = (detailedStats[key] || 0) + 1;

                // 2. Industry Stats (Global)
                if (record.industry) {
                    industryStats[record.industry] = (industryStats[record.industry] || 0) + 1;
                }
            }
        });

        // Convert detailedStats to a cleaner JSON array for the LLM
        const breakdown = Object.entries(detailedStats).map(([key, count]) => {
            const [program, batch, status] = key.split('|');
            return { program, batch, status, count };
        });

        // Get top industries
        const topIndustries = Object.entries(industryStats)
            .sort((a, b) => b[1] - a[1])
            .slice(0, 10)
            .map(([name, count]) => ({ name, count }));

        return {
            summary: {
                total_records_analyzed: totalRecords,
                generated_at: new Date().toISOString()
            },
            // The "Cube" data structure allowing slicing by Program or Batch
            data_breakdown: breakdown, 
            top_industries: topIndustries
        };

    } catch (error) {
        console.error("Context Gather Error:", error);
        return { error: "Failed to retrieve database context." };
    }
};

export const sendMessageToPaulo = async (message: string, history: any[]) => {
    try {
        const contextData = await getSystemContext();

        const systemPrompt = `
        You are P.A.U.L.O (Placement, Alumni, University Linkages Office), an advanced AI assistant for the Admin of Laguna University's Alumni Tracer System.

        **Your Capabilities:**
        You have access to a structured database snapshot. You can answer complex questions involving filters like **Program/Course**, **Batch/Year**, and **Employment Status**.

        **Data Structure:**
        The 'data_breakdown' is an array of objects: { "program": "BSIT", "batch": "2023", "status": "Employed", "count": 5 }.

        **How to Answer:**
        1. **Filtering:** If the user asks "How many BSIT students are employed?", you must sum the 'count' of all items in 'data_breakdown' where program="BSIT" and status="Employed".
        2. **Batch Specifics:** If asked about "Batch 2022", filter by batch="2022".
        3. **General Stats:** If no filter is specified, sum up counts globally.
        4. **Charts:** Always verify if the user wants a visualization.

        **Current System Data (Context):**
        ${JSON.stringify(contextData, null, 2)}

        **Chart Generation Rules:**
        If the user asks to visualize data (e.g., "Chart of BSIT employment", "Graph industries"), output this JSON structure at the END of your response:

        :::CHART_DATA:::
        {
          "type": "bar" | "pie",
          "title": "Chart Title",
          "data": [
            {"name": "Label1", "value": 10},
            {"name": "Label2", "value": 20}
          ]
        }
        :::END_CHART:::

        **Tone:** Professional, precise, and data-driven. Do not hallucinate numbers. If data is missing for a specific query (e.g., a batch that doesn't exist), state that no records were found.
        `;

        // Format history for Gemini
        const chatHistory = history.map(h => ({
            role: h.sender === 'user' ? 'user' : 'model',
            parts: [{ text: h.text }]
        }));

        const chat = ai.chats.create({
            model: MODEL,
            config: {
                systemInstruction: systemPrompt,
                temperature: 0.2, // Lower temperature for more accurate math/filtering
            },
            history: chatHistory
        });

        const result = await chat.sendMessage({ message: message });
        const responseText = result.text;

        // Parse for Chart Data
        let chartData = null;
        let cleanText = responseText;

        const chartRegex = /:::CHART_DATA:::([\s\S]*?):::END_CHART:::/;
        const match = responseText.match(chartRegex);

        if (match && match[1]) {
            try {
                chartData = JSON.parse(match[1]);
                cleanText = responseText.replace(match[0], '').trim();
            } catch (e) {
                console.error("Failed to parse chart JSON from AI", e);
            }
        }

        return {
            text: cleanText,
            chart: chartData
        };

    } catch (error) {
        console.error("PAULO Error:", error);
        return { text: "I'm encountering a connection error with my neural link. Please try again later.", chart: null };
    }
};

