                const fullName = `${userProfile.first_name} ${userProfile.last_name}`;
                const program = userProfile.program || "Unknown Program";
                const batch = userProfile.year_level || "Unknown Batch";
                const status = record.employment_status || "Unknown Status";
                const company = record.company_name || record.business_name || "N/A";
                const position = record.current_position || "N/A";

                // Add to Roster (The "Brain" of the AI)
                alumniRoster.push({
                    name: fullName,
                    program: program,
                    batch: batch,
                    status: status,
                    company: company,
                    position: position,
                    alignment: record.job_alignment || "N/A"
                });

                // 2. Industry Stats (Global)
                if (record.industry) {
                    industryStats[record.industry] = (industryStats[record.industry] || 0) + 1;
                }
            }
        });

        // Get top industries
        const topIndustries = Object.entries(industryStats)
            .sort((a, b) => b[1] - a[1])
            .slice(0, 10)
            .map(([name, count]) => ({ name, count }));

        return {
            summary: {
                total_records_analyzed: totalRecords,
                generated_at: new Date().toISOString()
            },
            // Full list of alumni with details
            alumni_roster: alumniRoster, 
            top_industries: topIndustries
        };

    } catch (error) {
        console.error("Context Gather Error:", error);
        return { error: "Failed to retrieve database context." };
    }
};

export const sendMessageToPaulo = async (message: string, history: any[]) => {
    try {
        const contextData = await getSystemContext();

        const systemPrompt = `
        You are P.A.U.L.O (Placement, Alumni, University Linkages Office), an advanced AI assistant for the Admin of Laguna University's Alumni Tracer System.

        **Your Superpower:**
        You have access to the **Full Alumni Roster**. You know exactly who is employed, who is unemployed, where they work, and their batch/program.

        **Data Access (Context):**
        ${JSON.stringify(contextData, null, 2)}

        **How to Answer:**
        1. **Specific Names:** If asked "Who are the employed BSIT students?", list their names from the 'alumni_roster' where program matches 'BSIT' and status is 'Employed'.
        2. **Lookup:** If asked "Where does Juan Dela Cruz work?", find his name in the roster and return his 'company' and 'position'.
        3. **Lists:** When listing people, use bullet points. If the list is very long (>10 people), list the first 10 and say "and [x] others...".
        4. **Aggregation:** You can still answer general stats questions by counting the roster yourself.
        5. **Charts:** Always verify if the user wants a visualization.

        **Chart Generation Rules:**
        If the user asks to visualize data (e.g., "Chart of BSIT employment", "Graph industries"), output this JSON structure at the END of your response:

        :::CHART_DATA:::
        {
          "type": "bar" | "pie",
          "title": "Chart Title",
          "data": [
            {"name": "Label1", "value": 10},
            {"name": "Label2", "value": 20}
          ]
        }
        :::END_CHART:::

        **Tone:** Professional, helpful, and precise. 
        `;

        // Format history for Gemini
        const chatHistory = history.map(h => ({
            role: h.sender === 'user' ? 'user' : 'model',
            parts: [{ text: h.text }]
        }));

        const chat = ai.chats.create({
            model: MODEL,
            config: {
                systemInstruction: systemPrompt,
                temperature: 0.2, // Lower temperature for accurate retrieval
            },
            history: chatHistory
        });

        const result = await chat.sendMessage({ message: message });
        const responseText = result.text;

        // Parse for Chart Data
        let chartData = null;
        let cleanText = responseText;

        const chartRegex = /:::CHART_DATA:::([\s\S]*?):::END_CHART:::/;
        const match = responseText.match(chartRegex);

        if (match && match[1]) {
            try {
                chartData = JSON.parse(match[1]);
                cleanText = responseText.replace(match[0], '').trim();
            } catch (e) {
                console.error("Failed to parse chart JSON from AI", e);
            }
        }

        return {
            text: cleanText,
            chart: chartData
        };

    } catch (error) {
        console.error("PAULO Error:", error);
        return { text: "I'm encountering a connection error with my neural link. Please try again later.", chart: null };
    }
};

