import { GoogleGenAI } from "@google/genai";
import { supabase } from '../lib/supabaseClient';

const API_KEY = "AIzaSyDUo8NlOC56gWYEETviAceCUd-mxoruplQ";
const ai = new GoogleGenAI({ apiKey: API_KEY });

// Using gemini-3-flash-preview for large context window and reasoning
const MODEL = "gemini-3-flash-preview";

// --- Context Gathering ---
const getSystemContext = async () => {
    try {
        // 1. Fetch Employment Data
        const { data: empData, error: empError } = await supabase
            .from('employment_information')
            .select('survey_response_id, employment_status, industry, job_alignment, company_name, business_name, current_position');

        if (empError) throw empError;

        // 2. Fetch Survey Mapping
        const { data: surveys, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id, student_id, alumni_id, respondent_type');

        if (surveyError) throw surveyError;

        // 3. Fetch User Profiles (Students & Alumni) for Program/Batch info
        const [ { data: students }, { data: alumni } ] = await Promise.all([
            supabase.from('students').select('id, first_name, last_name, program, year_level'),
            supabase.from('alumni').select('id, first_name, last_name, program, year_level')
        ]);

        // --- Data Linking & Aggregation ---

        // Maps for O(1) lookup
        const surveyMap = new Map(surveys?.map((s: any) => [s.id, s]));
        const studentMap = new Map(students?.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni?.map((a: any) => [a.id, a]));

        // Aggregation Containers
        const industryStats: Record<string, number> = {};

        // Detailed Roster for Name-Based Queries
        const alumniRoster: any[] = [];

        let totalRecords = 0;

        empData?.forEach(record => {
            const survey = surveyMap.get(record.survey_response_id) as any;
            if (!survey) return;

            let userProfile: any = null;
            if (survey.respondent_type === 'student') {
                userProfile = studentMap.get(survey.student_id);
            } else {
                userProfile = alumniMap.get(survey.alumni_id);
            }

            if (userProfile) {
                totalRecords++;
                const fullName = `${userProfile.first_name} ${userProfile.last_name}`;
                const program = userProfile.program || "Unknown Program";
                const batch = userProfile.year_level || "Unknown Batch";
                const status = record.employment_status || "Unknown Status";
                const company = record.company_name || record.business_name || "N/A";
                const position = record.current_position || "N/A";

                // Add to Roster (The "Brain" of the AI)
                alumniRoster.push({
                    name: fullName,
                    program: program,
                    batch: batch,
                    status: status,
                    company: company,
                    position: position,
                    alignment: record.job_alignment || "N/A"
                });

                // 2. Industry Stats (Global)
                if (record.industry) {
                    industryStats[record.industry] = (industryStats[record.industry] || 0) + 1;
                }
            }
        });

        // Get top industries
        const topIndustries = Object.entries(industryStats)
            .sort((a, b) => b[1] - a[1])
            .slice(0, 10)
            .map(([name, count]) => ({ name, count }));

        return {
            summary: {
                total_records_analyzed: totalRecords,
                generated_at: new Date().toISOString()
            },
            // Full list of alumni with details
            alumni_roster: alumniRoster, 
            top_industries: topIndustries
        };

    } catch (error) {
        console.error("Context Gather Error:", error);
        return { error: "Failed to retrieve database context." };
    }
};

export const sendMessageToPaulo = async (message: string, history: any[]) => {
    try {
        const contextData = await getSystemContext();

        const systemPrompt = `
        You are P.A.U.L.O (Placement, Alumni, University Linkages Office), an advanced AI assistant for the Admin of Laguna University's Alumni Tracer System.

        **CRITICAL INSTRUCTION FOR ACCURACY:**
        You have access to a specific JSON dataset below called "alumni_roster". When the user asks about a specific person, you MUST search this roster.

        1. **Exact & Fuzzy Matching:** If the user asks for "Juan", look for "Juan Dela Cruz" or anyone with "Juan" in their name.
        2. **Fact-Based Answers:** Only answer based on the provided context. If a name is not in the roster, say "I cannot find a record for [Name] in the current employment database."
        3. **Job Details:** When asked "Where does [Name] work?", provide their 'company', 'position', and 'status'.

        **Data Access (Context):**
        ${JSON.stringify(contextData, null, 2)}

        **How to Answer:**
        1. **Specific Names:** If asked "Who are the employed BSIT students?", list their names from the 'alumni_roster' where program matches 'BSIT' and status is 'Employed'.
        2. **Lookup:** If asked "Where does Juan Dela Cruz work?", find his name in the roster and return his 'company' and 'position'.
        3. **Lists:** When listing people, use bullet points. If the list is very long (>10 people), list the first 10 and say "and [x] others...".
        4. **Aggregation:** You can still answer general stats questions by counting the roster yourself.
        5. **Charts:** Always verify if the user wants a visualization.

        **Chart Generation Rules:**
        If the user asks to visualize data (e.g., "Chart of BSIT employment", "Graph industries"), output this JSON structure at the END of your response:

        :::CHART_DATA:::
        {
          "type": "bar" | "pie",
          "title": "Chart Title",
          "data": [
            {"name": "Label1", "value": 10},
            {"name": "Label2", "value": 20}
          ]
        }
        :::END_CHART:::

        **Tone:** Professional, helpful, and precise. 
        `;

        // Format history for Gemini
        const chatHistory = history.map(h => ({
            role: h.sender === 'user' ? 'user' : 'model',
            parts: [{ text: h.text }]
        }));

        const chat = ai.chats.create({
            model: MODEL,
            config: {
                systemInstruction: systemPrompt,
                temperature: 0.1, // Very low temperature for high factual accuracy
            },
            history: chatHistory
        });

        const result = await chat.sendMessage({ message: message });
        const responseText = result.text;

        // Parse for Chart Data
        let chartData = null;
        let cleanText = responseText;

        const chartRegex = /:::CHART_DATA:::([\s\S]*?):::END_CHART:::/;
        const match = responseText.match(chartRegex);

        if (match && match[1]) {
            try {
                chartData = JSON.parse(match[1]);
                cleanText = responseText.replace(match[0], '').trim();
            } catch (e) {
                console.error("Failed to parse chart JSON from AI", e);
            }
        }

        return {
            text: cleanText,
            chart: chartData
        };

    } catch (error) {
        console.error("PAULO Error:", error);
        return { text: "I'm encountering a connection error with my neural link. Please try again later.", chart: null };
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { Send, Bot, User, RefreshCw, Mic, StopCircle } from 'lucide-react';
import { sendMessageToPaulo } from '../services/pauloService';
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, PieChart, Pie, Cell, Legend } from 'recharts';

interface Message {
  id: string;
  sender: 'user' | 'paulo';
  text: string;
  chart?: {
    type: 'bar' | 'pie';
    title: string;
    data: { name: string; value: number }[];
  } | null;
  timestamp: Date;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#10b981', '#f59e0b', '#3b82f6'];

const PauloPage: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      sender: 'paulo',
      text: "Hello, Administrator. I am P.A.U.L.O. (Placement, Alumni, University Linkages Office) Assistant. I have access to the latest system metrics. How can I assist you today?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const transcriptRef = useRef<string>(''); // Holds latest voice text for immediate sending

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const scrollToBottom = () => {
    scrollRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const handleSend = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const textToSend = overrideText || input;

    if (!textToSend.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      sender: 'user',
      text: textToSend,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Call AI
    const history = messages.map(m => ({ sender: m.sender, text: m.text }));
    const response = await sendMessageToPaulo(userMsg.text, history);

    const botMsg: Message = {
      id: (Date.now() + 1).toString(),
      sender: 'paulo',
      text: response.text,
      chart: response.chart,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, botMsg]);
    setIsTyping(false);
  };

  const handleQuickPrompt = (prompt: string) => {
      setInput(prompt);
      // Optional: Auto submit
      // handleSend(); 
  };

  const startListening = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
        alert("Voice input is not supported in this browser. Please use Google Chrome or Edge.");
        return;
    }

    if (recognitionRef.current) {
        recognitionRef.current.stop(); // Ensure clean start
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'en-US';
    recognition.interimResults = true; // See results as we speak
    recognition.continuous = false; // Stop automatically when silence is detected

    recognition.onstart = () => {
        setIsListening(true);
        transcriptRef.current = '';
    };

    recognition.onresult = (event: any) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
            if (event.results[i].isFinal) {
                finalTranscript += event.results[i][0].transcript;
            } else {
                // Interim
                finalTranscript += event.results[i][0].transcript;
            }
        }

        // Update both state (for UI) and ref (for logic)
        setInput(finalTranscript);
        transcriptRef.current = finalTranscript;
    };

    recognition.onerror = (event: any) => {
        console.error("Speech recognition error", event.error);
        setIsListening(false);
        if (event.error === 'not-allowed') {
            alert("Microphone access blocked. Please allow microphone permission in your browser settings.");
        }
    };

    recognition.onend = () => {
        setIsListening(false);
        // AUTO SEND LOGIC: If we have text, send it immediately
        if (transcriptRef.current.trim().length > 0) {
            handleSend(undefined, transcriptRef.current);
            transcriptRef.current = ''; // Reset
        }
    };

    recognitionRef.current = recognition;
    recognition.start();
  };

  const stopListening = () => {
      if (recognitionRef.current) {
          recognitionRef.current.stop();
          // onend will fire and trigger the send
      }
  };

  // --- TEXT FORMATTER ---
  const formatText = (text: string) => {
    if (!text) return null;

    return text.split('\n').map((line, i) => {
      let content = line;
      let wrapperClass = "min-h-[1.2em]"; // Keeps empty lines visible

      // Handle Headings
      if (content.startsWith('### ')) {
          content = content.substring(4);
          wrapperClass = "font-bold text-md mt-3 mb-1";
      } else if (content.startsWith('## ')) {
          content = content.substring(3);
          wrapperClass = "font-bold text-lg mt-4 mb-2";
      } else if (content.startsWith('# ')) {
          content = content.substring(2);
          wrapperClass = "font-black text-xl mt-4 mb-2";
      }

      // Handle Bullets
      const trimmed = content.trim();
      const isBullet = trimmed.startsWith('* ') || trimmed.startsWith('- ');
      if (isBullet) {
          content = trimmed.substring(2);
      }

      // Handle Bold Parsing (**text**)
      const parts = content.split(/(\*\*.*?\*\*)/g).map((part, index) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={index} className="font-bold">{part.slice(2, -2)}</strong>;
        }
        return <span key={index}>{part}</span>;
      });

      if (isBullet) {
        return (
          <div key={i} className="flex items-start gap-2 ml-2 mb-1">
             <span className="mt-2 w-1.5 h-1.5 bg-current rounded-full shrink-0 opacity-60"></span>
             <span className="leading-relaxed">{parts}</span>
          </div>
        );
      }

      return <div key={i} className={`${wrapperClass} leading-relaxed`}>{parts}</div>;
    });
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 relative overflow-hidden">

        {/* Background Effects */}
        <div className="absolute inset-0 pointer-events-none">
            <div className="absolute -top-[20%] -left-[10%] w-[50%] h-[50%] rounded-full bg-indigo-500/5 blur-[120px]"></div>
            <div className="absolute bottom-[10%] -right-[10%] w-[40%] h-[40%] rounded-full bg-blue-500/5 blur-[100px]"></div>
        </div>

        {/* Header */}
        <div className="bg-white/80 backdrop-blur-xl border-b border-slate-200 p-4 flex items-center justify-between z-20 sticky top-0">
            <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-600 to-blue-600 flex items-center justify-center shadow-lg shadow-indigo-200">
                    <Bot className="text-white w-6 h-6" />
                </div>
                <div>
                    <h1 className="font-black text-slate-800 text-lg tracking-tight flex items-center gap-2">
                        P.A.U.L.O. <span className="px-2 py-0.5 rounded-full bg-indigo-100 text-indigo-700 text-[10px] font-bold uppercase">AI Online</span>
                    </h1>
                    <p className="text-xs text-slate-500 font-medium">Placement Alumni University Linkages Office Assistant</p>
                </div>
            </div>
            <button 
                onClick={() => setMessages([{ id: 'reset', sender: 'paulo', text: "Memory cleared. How can I help?", timestamp: new Date() }])}
                className="p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-600 transition-colors"
                title="Reset Conversation"
            >
                <RefreshCw size={18} />
            </button>
        </div>

        {/* Chat Area */}
        <div className="flex-grow overflow-y-auto p-4 md:p-6 space-y-6 z-10 custom-scrollbar">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex w-full ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`flex max-w-[90%] md:max-w-[80%] gap-3 ${msg.sender === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>

                        {/* Avatar */}
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 shadow-sm ${msg.sender === 'paulo' ? 'bg-white border border-indigo-100 text-indigo-600' : 'bg-slate-800 text-white'}`}>
                            {msg.sender === 'paulo' ? <Bot size={16} /> : <User size={16} />}
                        </div>

                        {/* Bubble */}
                        <div className={`flex flex-col gap-2 ${msg.sender === 'user' ? 'items-end' : 'items-start'}`}>
                            <div className={`px-5 py-3.5 rounded-2xl shadow-sm text-sm ${
                                msg.sender === 'user' 
                                ? 'bg-slate-800 text-white rounded-tr-none' 
                                : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none'
                            }`}>
                                {/* Use formatText helper instead of rendering raw string */}
                                {formatText(msg.text)}
                            </div>

                            {/* Chart Rendering */}
                            {msg.chart && (
                                <div className="w-full max-w-lg bg-white p-4 rounded-2xl border border-slate-200 shadow-lg mt-2 animate-in fade-in slide-in-from-bottom-4">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-4 text-center">{msg.chart.title}</h4>
                                    <div className="h-64 w-full">
                                        <ResponsiveContainer width="100%" height="100%">
                                            {msg.chart.type === 'bar' ? (
                                                <BarChart data={msg.chart.data} layout="vertical" margin={{left: 30}}>
                                                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} opacity={0.3}/>
                                                    <XAxis type="number" hide />
                                                    <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 10}} />
                                                    <Tooltip contentStyle={{borderRadius: '8px', border: 'none'}} />
                                                    <Bar dataKey="value" fill="#6366f1" radius={[0, 4, 4, 0]} barSize={20} />
                                                </BarChart>
                                            ) : (
                                                <PieChart>
                                                    <Pie
                                                        data={msg.chart.data}
                                                        cx="50%"
                                                        cy="50%"
                                                        innerRadius={60}
                                                        outerRadius={80}
                                                        paddingAngle={5}
                                                        dataKey="value"
                                                    >
                                                        {msg.chart.data.map((entry, index) => (
                                                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
